"use client";

import Link from "next/link";
import { Github, Linkedin, Twitter } from "lucide-react";

export default function Footer() {
  return (
    <footer className="relative mt-20 border-t border-white/10 bg-slate-900 text-white">
      
      {/* Glow */}
      <div className="absolute inset-0 bg-gradient-to-tr from-indigo-500/10 via-transparent to-sky-500/10 blur-2xl pointer-events-none" />

      <div className="relative max-w-7xl mx-auto px-6 py-12">
        
        <div className="grid gap-10 md:grid-cols-4">
          
          {/* Brand */}
          <div>
            <h2 className="text-lg font-semibold mb-3">
              Healthcare System
            </h2>
            <p className="text-sm text-gray-400">
              Secure, decentralized healthcare powered by blockchain.
              Protecting patient data with transparency and trust.
            </p>
          </div>

          {/* Product */}
          <div>
            <h3 className="text-sm font-semibold mb-3 text-gray-300">
              Product
            </h3>
            <ul className="space-y-2 text-sm text-gray-400">
              <li><Link href="/">Home</Link></li>
              <li><Link href="/auth/login">Login</Link></li>
              <li><Link href="/auth/register">Register</Link></li>
            </ul>
          </div>

          {/* Roles */}
          <div>
            <h3 className="text-sm font-semibold mb-3 text-gray-300">
              Roles
            </h3>
            <ul className="space-y-2 text-sm text-gray-400">
              <li>Patients</li>
              <li>Doctors</li>
              <li>Government</li>
            </ul>
          </div>

          {/* Social */}
          <div>
            <h3 className="text-sm font-semibold mb-3 text-gray-300">
              Connect
            </h3>

            <div className="flex gap-3">
              
              <a
                href="#"
                className="p-2 rounded-lg bg-white/5 border border-white/10 hover:bg-white/10 transition"
              >
                <Github size={18} />
              </a>

              <a
                href="#"
                className="p-2 rounded-lg bg-white/5 border border-white/10 hover:bg-white/10 transition"
              >
                <Linkedin size={18} />
              </a>

              <a
                href="#"
                className="p-2 rounded-lg bg-white/5 border border-white/10 hover:bg-white/10 transition"
              >
                <Twitter size={18} />
              </a>

            </div>
          </div>
        </div>

        {/* Bottom */}
        <div className="mt-10 pt-6 border-t border-white/10 text-center text-sm text-gray-500">
          © {new Date().getFullYear()} Healthcare System. All rights reserved.
        </div>
      </div>
    </footer>
  );
}